28	/**
29	 * @brief Helper method that computes the seed gain of the given atom block.
30	 *
31	 * The seed_type variable selects which algorithm to use to compute the seed
32	 * gain.
33	 */
34	static inline float get_seed_gain(AtomBlockId blk_id,
35	                                  const AtomNetlist& atom_netlist,
36	                                  const Prepacker& prepacker,
37	                                  const LogicalModels& models,
38	                                  const e_cluster_seed seed_type,
39	                                  const t_molecule_stats& max_molecule_stats,
40	                                  const vtr::vector<AtomBlockId, float>& atom_criticality) {
41	    switch (seed_type) {
42	        // By criticality.
43	        // Intuition: starting a cluster with primitives that have timing-
44	        //            critical connections may help timing.
45	        case e_cluster_seed::TIMING:
46	            return atom_criticality[blk_id];
47	        // By number of used molecule input pins.
48	        // Intuition: molecules that use more inputs can be difficult to legally
49	        //            pack into partially full clusters. Use them as seeds
50	        //            instead.
51	        case e_cluster_seed::MAX_INPUTS: {
52	            PackMoleculeId blk_mol_id = prepacker.get_atom_molecule(blk_id);
53	            const t_molecule_stats molecule_stats = prepacker.calc_molecule_stats(blk_mol_id, atom_netlist, models);
54	            return molecule_stats.num_used_ext_inputs;
55	        }
56	        // By blended gain (criticality and inputs used).
57	        case e_cluster_seed::BLEND: {
58	            // Score seed gain of each block as a weighted sum of timing
59	            // criticality, number of tightly coupled blocks connected to
60	            // it, and number of external inputs.
61	            float seed_blend_fac = 0.5f;
62	
63	            PackMoleculeId blk_mol_id = prepacker.get_atom_molecule(blk_id);
64	            const t_molecule_stats molecule_stats = prepacker.calc_molecule_stats(blk_mol_id, atom_netlist, models);
65	            VTR_ASSERT(max_molecule_stats.num_used_ext_inputs > 0);
66	
67	            float used_ext_input_pin_ratio = vtr::safe_ratio<float>(molecule_stats.num_used_ext_inputs, max_molecule_stats.num_used_ext_inputs);
68	            float blend_gain = (seed_blend_fac * atom_criticality[blk_id]
69	                                + (1 - seed_blend_fac) * used_ext_input_pin_ratio);
70	            blend_gain *= (1 + 0.2 * (molecule_stats.num_blocks - 1));
71	            return blend_gain;
72	        }
73	        // By pins per molecule (i.e. available pins on primitives, not pins in use).
74	        // Intuition (a weak one): primitive types with more pins might be
75	        //                         harder to pack.
76	        case e_cluster_seed::MAX_PINS: {
77	            PackMoleculeId blk_mol_id = prepacker.get_atom_molecule(blk_id);
78	            const t_molecule_stats molecule_stats = prepacker.calc_molecule_stats(blk_mol_id, atom_netlist, models);
79	            return molecule_stats.num_pins;
80	        }
81	        // By input pins per molecule (i.e. available pins on primitives, not pins in use).
82	        // Intuition (a weak one): primitive types with more input pins might be
83	        //                         harder to pack.
84	        case e_cluster_seed::MAX_INPUT_PINS: {
85	            PackMoleculeId blk_mol_id = prepacker.get_atom_molecule(blk_id);
86	            const t_molecule_stats molecule_stats = prepacker.calc_molecule_stats(blk_mol_id, atom_netlist, models);
87	            return molecule_stats.num_input_pins;
88	        }
89	        case e_cluster_seed::BLEND2: {
90	            PackMoleculeId mol_id = prepacker.get_atom_molecule(blk_id);
91	            const t_molecule_stats molecule_stats = prepacker.calc_molecule_stats(mol_id, atom_netlist, models);
92	
93	            float pin_ratio = vtr::safe_ratio<float>(molecule_stats.num_pins, max_molecule_stats.num_pins);
94	            float input_pin_ratio = vtr::safe_ratio<float>(molecule_stats.num_input_pins, max_molecule_stats.num_input_pins);
95	            float output_pin_ratio = vtr::safe_ratio<float>(molecule_stats.num_output_pins, max_molecule_stats.num_output_pins);
96	            float used_ext_pin_ratio = vtr::safe_ratio<float>(molecule_stats.num_used_ext_pins, max_molecule_stats.num_used_ext_pins);
97	            float used_ext_input_pin_ratio = vtr::safe_ratio<float>(molecule_stats.num_used_ext_inputs, max_molecule_stats.num_used_ext_inputs);
98	            float used_ext_output_pin_ratio = vtr::safe_ratio<float>(molecule_stats.num_used_ext_outputs, max_molecule_stats.num_used_ext_outputs);
99	            float num_blocks_ratio = vtr::safe_ratio<float>(molecule_stats.num_blocks, max_molecule_stats.num_blocks);
100	            float criticality = atom_criticality[blk_id];
101	
102	            constexpr float PIN_WEIGHT = 0.;
103	            constexpr float INPUT_PIN_WEIGHT = 0.5;
104	            constexpr float OUTPUT_PIN_WEIGHT = 0.;
105	            constexpr float USED_PIN_WEIGHT = 0.;
106	            constexpr float USED_INPUT_PIN_WEIGHT = 0.2;
107	            constexpr float USED_OUTPUT_PIN_WEIGHT = 0.;
108	            constexpr float BLOCKS_WEIGHT = 0.2;
109	            constexpr float CRITICALITY_WEIGHT = 0.1;
110	
111	            float gain = PIN_WEIGHT * pin_ratio
112	                         + INPUT_PIN_WEIGHT * input_pin_ratio
113	                         + OUTPUT_PIN_WEIGHT * output_pin_ratio
114	
115	                         + USED_PIN_WEIGHT * used_ext_pin_ratio
116	                         + USED_INPUT_PIN_WEIGHT * used_ext_input_pin_ratio
117	                         + USED_OUTPUT_PIN_WEIGHT * used_ext_output_pin_ratio
118	
119	                         + BLOCKS_WEIGHT * num_blocks_ratio
120	                         + CRITICALITY_WEIGHT * criticality;
121	
122	            return gain;
123	        }
124	        default:
125	            VPR_FATAL_ERROR(VPR_ERROR_PACK, "Unrecognized cluster seed type");
126	            return 0.f;
127	    }
128	}
129	
130	/**
131	 * @brief Helper method to print the seed gains of each Atom block and their
132	 *        criticalities.
133	 */
134	static inline void print_seed_gains(const char* fname,
135	                                    const std::vector<PackMoleculeId>& seed_mols,
136	                                    const vtr::vector<PackMoleculeId, float>& molecule_gain,
137	                                    const vtr::vector<AtomBlockId, float>& atom_criticality,
138	                                    const AtomNetlist& atom_netlist,
139	                                    const LogicalModels& models,
140	                                    const Prepacker& prepacker) {
141	    FILE* fp = vtr::fopen(fname, "w");
142	
143	    // For pretty formatting determine the maximum name length
144	    int max_name_len = strlen("atom_block_name");
145	    int max_type_len = strlen("atom_block_type");
146	    for (auto blk_id : atom_netlist.blocks()) {
147	        max_name_len = std::max(max_name_len, (int)atom_netlist.block_name(blk_id).size());
148	
149	        std::string model_name = models.model_name(atom_netlist.block_model(blk_id));
150	        max_type_len = std::max<int>(max_type_len, model_name.size());
151	    }
152	
153	    fprintf(fp, "%-*s %-*s %8s %8s\n", max_name_len, "atom_block_name", max_type_len, "atom_block_type", "gain", "criticality");
154	    fprintf(fp, "\n");
155	    for (auto mol_id : seed_mols) {
156	        for (AtomBlockId blk_id : prepacker.get_molecule(mol_id).atom_block_ids) {
157	            if (!blk_id.is_valid()) {
158	                continue;
159	            }
160	            std::string name = atom_netlist.block_name(blk_id);
161	            fprintf(fp, "%-*s ", max_name_len, name.c_str());
162	
163	            std::string model_name = models.model_name(atom_netlist.block_model(blk_id));
164	            fprintf(fp, "%-*s ", max_type_len, model_name.c_str());
165	
166	            fprintf(fp, "%*f ", std::max((int)strlen("gain"), 8), molecule_gain[mol_id]);
167	            fprintf(fp, "%*f ", std::max((int)strlen("criticality"), 8), atom_criticality[blk_id]);
168	            fprintf(fp, "\n");
169	        }
170	    }
171	
172	    fclose(fp);
173	}
174	
175	GreedySeedSelector::GreedySeedSelector(const AtomNetlist& atom_netlist,
176	                                       const Prepacker& prepacker,
177	                                       const e_cluster_seed seed_type,
178	                                       const t_molecule_stats& max_molecule_stats,
179	                                       const LogicalModels& models,
180	                                       const PreClusterTimingManager& pre_cluster_timing_manager,
181	                                       const RamMapper& ram_mapper)
182	    : seed_mols_(prepacker.molecules().begin(), prepacker.molecules().end()) {
183	    // Seed molecule list is initialized with all molecule in the netlist.
184	
185	    // Pre-compute the criticality of each atom
186	    // Default criticalities set to zero (e.g. if not timing driven)
187	    vtr::vector<AtomBlockId, float> atom_criticality(atom_netlist.blocks().size(), 0.0f);
188	    if (pre_cluster_timing_manager.is_valid()) {
189	        // If the timing manager is valid (meaning the packing is timing driven)
190	        // compute the criticality of each atom.
191	        for (AtomBlockId atom_blk_id : atom_netlist.blocks()) {
192	            atom_criticality[atom_blk_id] = pre_cluster_timing_manager.calc_atom_setup_criticality(atom_blk_id, atom_netlist);
193	        }
194	    }
195	
196	    // Maintain a lookup table of the seed gain for each molecule. This will be
197	    // used to sort the seed molecules.
198	    // Initially all gains are zero.
199	    vtr::vector<PackMoleculeId, float> molecule_gains(seed_mols_.size(), 0.f);
200	
201	    // Get the seed gain of each molecule.
202	    for (PackMoleculeId mol_id : seed_mols_) {
203	        // Gain of each molecule is the maximum gain of its atoms
204	        float mol_gain = std::numeric_limits<float>::lowest();
205	        const std::vector<AtomBlockId>& molecule_atoms = prepacker.get_molecule(mol_id).atom_block_ids;
206	        for (AtomBlockId blk_id : molecule_atoms) {
207	            // If the molecule does not fit the entire pack pattern, it's possible to have invalid block ids in the molecule_atoms vector
208	            if (blk_id == AtomBlockId::INVALID()) {
209	                continue;
210	            }
211	            float atom_gain = get_seed_gain(blk_id,
212	                                            atom_netlist,
213	                                            prepacker,
214	                                            models,
215	                                            seed_type,
216	                                            max_molecule_stats,
217	                                            atom_criticality);
218	            mol_gain = std::max(mol_gain, atom_gain);
219	        }
220	        molecule_gains[mol_id] = mol_gain;
221	    }
222	
223	    // Sort seeds in descending order of seed gain (i.e. highest seed gain first)
224	    //
225	    // Note that we use a *stable* sort here. It has been observed that different
226	    // standard library implementations (e.g. gcc-4.9 vs gcc-5) use sorting algorithms
227	    // which produce different orderings for seeds of equal gain (which is allowed with
228	    // std::sort which does not specify how equal values are handled). Using a stable
229	    // sort ensures that regardless of the underlying sorting algorithm the same seed
230	    // order is produced regardless of compiler.
231	    auto by_descending_gain = [&](const PackMoleculeId lhs, const PackMoleculeId rhs) {
232	        return molecule_gains[lhs] > molecule_gains[rhs];
233	    };
234	    std::stable_sort(seed_mols_.begin(), seed_mols_.end(), by_descending_gain);
235	
236	    // If there are RAM groups, move RAM seeds to the front so that RAM clusters
237	    // are formed first. Since the RAM mapper has full information about which
238	    // atoms belong together, packing RAM clusters early gives non-RAM clusters
239	    // transitive connectivity information and makes ordering more intuitive.
240	    if (ram_mapper.num_groups() > 0) {
241	        std::stable_partition(seed_mols_.begin(), seed_mols_.end(),
242	                              [&](PackMoleculeId mol_id) {
243	                                  const t_pack_molecule& mol = prepacker.get_molecule(mol_id);
244	                                  AtomBlockId root = mol.atom_block_ids[mol.root];
245	                                  return ram_mapper.group_id_of(root).is_valid();
246	                              });
247	    }
248	
249	    // Print the seed gains if requested.
250	    if (getEchoEnabled() && isEchoFileEnabled(E_ECHO_CLUSTERING_BLOCK_CRITICALITIES)) {
251	        print_seed_gains(getEchoFileName(E_ECHO_CLUSTERING_BLOCK_CRITICALITIES),
252	                         seed_mols_, molecule_gains, atom_criticality, atom_netlist, models, prepacker);
253	    }
254	
255	    // Set the starting seed index (the index of the first molecule to propose).
256	    // The index of the first seed to propose is the first molecule in the
257	    // seed molecules vector (i.e. the one with the highest seed gain).
258	    seed_index_ = 0;
259	}
260	
261	PackMoleculeId GreedySeedSelector::get_next_seed(const ClusterLegalizer& cluster_legalizer) {
262	    while (seed_index_ < seed_mols_.size()) {
263	        // Get the current seed molecule at the seed index and increment the
264	        // seed index.
265	        // All previous seed indices have been either proposed already or
266	        // are already clustered. This process assumes that once an atom
267	        // is clustered it will never become unclustered.
268	        PackMoleculeId seed_molecule_id = seed_mols_[seed_index_++];
269	
270	        // If this molecule has been clustered, it cannot be proposed as a seed.
271	        // Skip to the next seed.
272	        if (cluster_legalizer.is_mol_clustered(seed_molecule_id)) {
273	            continue;
274	        }
275	        return seed_molecule_id;
276	    }
277	
278	    // If the previous loop does not return a molecule, it implies that all
279	    // molecule have been clustered or have already been proposed as a seed.
280	    // Return nullptr to signify that there are no further seeds.
281	    return PackMoleculeId::INVALID();
282	}
