751	void GreedyCandidateSelector::add_general_cluster_molecule_candidates(
752	    ClusterGainStats& cluster_gain_stats,
753	    LegalizationClusterId legalization_cluster_id,
754	    const ClusterLegalizer& cluster_legalizer,
755	    AttractionInfo& attraction_groups) {
756	
757	    /*
758	     * @brief Get candidate molecule to pack into currently open cluster
759	     *
760	     * Molecule selection priority:
761	     * 1. Find unpacked molecules based on criticality and strong connectedness
762	     *    (connected by low fanout nets) with current cluster.
763	     * 2. Find unpacked molecules based on transitive connections (eg. 2 hops away)
764	     *    with current cluster.
765	     * 3. Find unpacked molecules based on weak connectedness (connected by high
766	     *    fanout nets) with current cluster.
767	     * 4. Find unpacked molecules based on attraction group of the current cluster
768	     *    (if the cluster has an attraction group).
769	     */
770	
